CREATE TABLE `site_settings` (
  `key` varchar(100) NOT NULL,
  `value` text NOT NULL,
  `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `site_settings_key` PRIMARY KEY(`key`)
);

-- Seed default visibility settings: all sections visible by default
INSERT INTO `site_settings` (`key`, `value`) VALUES
  ('webinar_sections_visibility', '{"evergreen":true,"exclusive":true,"recordings":true}'),
  ('guides_sections_visibility', '{"pdf":true,"checklist":true,"playbook":true,"other":true}');

